        if winner is not None:
            if winner == original_player:
                return 10000 + depth
            else:
                return -10000 - depth

        # For simplicity: only search for original player
        # Others take greedy moves
        legal_moves = self._get_legal_moves(board, original_player)

        if not legal_moves:
            return self._evaluate_board(board, original_player)

        max_value = -float('inf')

        for move in legal_moves:
            new_board = self._simulate_move(board.copy(), move, original_player)
            value = self._minimax(new_board, depth - 1, alpha, beta, original_player)
            max_value = max(max_value, value)
            alpha = max(alpha, value)
            if beta <= alpha:
