        if is_maximizing:
            max_value = -float('inf')
            for move in legal_moves:
                new_board = self._simulate_move(board.copy(), move, current_player)
                next_player = (current_player + 1) % 4
                value = self._minimax(new_board, depth - 1, alpha, beta, original_player, next_player, False)
                max_value = max(max_value, value)
                alpha = max(alpha, value)
                if beta <= alpha:
                    break
            return max_value
        else:
            min_value = float('inf')
            for move in legal_moves:
                new_board = self._simulate_move(board.copy(), move, current_player)
                next_player = (current_player + 1) % 4
                value = self._minimax(new_board, depth - 1, alpha, beta, original_player, next_player, True)
