    def _simulate_move(self, board, move, player):
        if move == Move.END_TURN:
            return board

        q, r = move.position.q, move.position.r
        direction = move.direction
        dq, dr = self.direction_vectors[direction]

        x, y = self._to_board(q, r)

        if move.is_jump:
            new_x, new_y = self._to_board(q + 2*dq, r + 2*dr)
        else:
            new_x, new_y = self._to_board(q + dq, r + dr)

        board[y, x] = -1
        board[new_y, new_x] = player

        return board

    def _check_winner(self, board):
        for player in range(4):
            if self._player_has_won(board, player):
                return player
        return None

    def _player_has_won(self, board, player):
        for x, y in self.goal_positions[player]:
            if board[y, x] != player:
                return False
        return True

    def _evaluate_board(self, board, player):
        """
        Heuristic: pieces in goal + distance to goal + blocking opponent.
        """
        score = 0.0

        player_goal = self.goal_positions[player]

        # Count pieces in goal area
        pieces_in_goal = sum(1 for (gx, gy) in player_goal if board[gy, gx] == player)
        score += pieces_in_goal * 1000.0  # Large bonus for pieces in goal

        # If all pieces in goal, player wins
        if pieces_in_goal == len(player_goal):
            return 10000.0

        # Calculate average distance to goal
        player_pieces = []
        for y in range(self.board_size):
            for x in range(self.board_size):
                if board[y, x] == player:
                    player_pieces.append((x, y))

        if player_pieces:
            total_dist = 0
            for x, y in player_pieces:
                q, r = self._to_axial(x, y)
                min_dist = float('inf')
                for gx, gy in player_goal:
