                    dist = (abs(q-gq) + abs(r-gr) + abs(-q-r - (-gq-gr))) // 2
                    min_dist = min(min_dist, dist)
                total_dist += min_dist
            avg_dist = total_dist / len(player_pieces)
            score -= avg_dist * 50.0  # Lower distance = higher score

        # Penalize opponent pieces in OUR goal area
        opponent = (player + 2) % 4
        for x, y in player_goal:
            if board[y, x] == opponent:
                score -= 200.0  # Opponent blocking our goal

        return score


