                            mid_x, mid_y = self._to_board(q + dq, r + dr)

                            if (0 <= jump_x < self.board_size and 0 <= jump_y < self.board_size and
                                0 <= mid_x < self.board_size and 0 <= mid_y < self.board_size):
                                if (board[jump_y, jump_x] == -1 and 
                                    board[mid_y, mid_x] >= 0 and board[mid_y, mid_x] != player):
                                    legal_moves.append(Move(q, r, direction, True))

