    def _evaluate_board(self, board, player):
        """
        Heuristic: pieces in goal + distance to goal + blocking opponent.
        """
        score = 0.0

        player_goal = self.goal_positions[player]

        # Count pieces in goal area
        pieces_in_goal = sum(1 for (gx, gy) in player_goal if board[gy, gx] == player)
        score += pieces_in_goal * 1000.0  # Large bonus for pieces in goal

        # If all pieces in goal, player wins
        if pieces_in_goal == len(player_goal):
